import React from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { Link } from 'react-router-dom';
import { logout } from '../actions/authActions';

function Navbar() {
  const user = useSelector((state) => state.auth.user);
  const dispatch = useDispatch();

  const handleLogout = () => {
    dispatch(logout());
  };

  return (
    <nav className="navbar navbar-expand-lg navbar-dark bg-primary">
      <div className="container-fluid">
        <Link className="navbar-brand" to="/">School App</Link>
        <div className="navbar-nav">
          {user && (
            <>
              {user.role === "admin" && (
                <li className="nav-item">
                  <Link className="nav-link" to="/admin">Админ</Link>
                </li>
              )}
              {user.role === "student" && (
                <li className="nav-item">
                  <Link className="nav-link" to="/courses">Курсы</Link>
                </li>
              )}
              {user.role === "teacher" && (
                <>
                  <li className="nav-item">
                    <Link className="nav-link" to="/courses">Курсы</Link>
                  </li>
                  <li className="nav-item">
                    <Link className="nav-link" to="/add-course">Добавить курс</Link>
                  </li>
                </>
              )}
              <li className="nav-item">
                <button className="nav-link btn btn-link" onClick={handleLogout}>Выход</button>
              </li>
            </>
          )}
        </div>
      </div>
    </nav>
  );
}

export default Navbar;
